<?php namespace App\Repositories\Accounting;use App\Repositories\BaseRepository;use App\Models\Accounting\BankReconciliation;use Illuminate\Database\Eloquent\Collection;class BankReconciliationRepository extends BaseRepository{    public function __construct(BankReconciliation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAccount(int $chartOfAccountId): Collection    {        return $this->findByField('chart_of_account_id', $chartOfAccountId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('reconciliation_date', [$startDate, $endDate])->get();    }    public function getPendingReconciliations(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getCompletedReconciliations(): Collection    {        return $this->query()->where('status', 'completed')->get();    }    public function getByMonth(int $month, int $year): Collection    {        return $this->query()->whereMonth('reconciliation_date', $month)->whereYear('reconciliation_date', $year)->get();    }    public function markAsCompleted(int $id, ?string $notes = null): bool    {        $data = ['status' => 'completed', 'completed_at' => now()];        if ($notes) {            $data['notes'] = $notes;        }        return $this->update($id, $data);    }    public function getLatestByAccount(int $chartOfAccountId): ?BankReconciliation    {        return $this->query()->where('chart_of_account_id', $chartOfAccountId)->orderBy('reconciliation_date', 'desc')->first();    }    public function findDiscrepancies(float $bankBalance, float $bookBalance): Collection    {        return $this->query()->whereRaw('ABS(bank_balance - book_balance) > ?', [0.01])->get();    }}